// PlotPanel (the main plot orchestrator — renders the collapsible time-course
// chart tile, the collapsible Σ barplot tile with its per-replicate CSV
// table, and embeds the stats panel), plus the smaller right-column UI
// affordances SampleSelectionOverlay (the sticky "Sample selection" pill
// with its popover grid) and ConditionEditor (the sidebar "Conditions" tile
// editor). Depends on the sibling chart + stats-panel modules; shared UI
// (ColorInput, AequorinStatsPanel consumers) resolves through shared.bundle.js
// and the co-located imports below.

import { Chart, InsetBarplot, FacetChartItem } from "./chart";
import { AequorinStatsPanel } from "./stats-panel";
import { AQ_ERROR_BAR_LABELS } from "./reports";
import { ColorInput, navigateToTool, setHandoff } from "../_shell";
import {
  convertTime,
  smooth,
  AnnotationSpec,
  ColInfo,
  Condition,
  ConditionEditorProps,
  PlotPanelHandle,
  PlotPanelProps,
  SampleSelectionOverlayProps,
  SeriesItem,
  SeriesRow,
} from "./helpers";

import { downloadPng, downloadSvg, fileBaseName } from "../_core/download";
import { downloadCsv, flashSaved } from "../_core/download";
import { useT } from "./i18n";
const { useState, useMemo, useRef, useEffect, useCallback } = React;

// ── PlotPanel ────────────────────────────────────────────────────────────────

export const PlotPanel = React.forwardRef<PlotPanelHandle, PlotPanelProps>(function PlotPanel(
  {
    stats,
    xStart,
    xEnd,
    yMin,
    yMax,
    faceted,
    title,
    subtitle,
    smoothWidth,
    plotBg,
    showGrid,
    lineWidth,
    ribbonOpacity,
    gridColor,
    plotHeight,
    timeStep,
    baseUnit,
    displayUnit,
    showInset,
    insetFillOpacity,
    insetBarWidth,
    insetBarGap,
    insetYMin,
    insetYMax,
    insetW,
    insetH,
    insetErrorType,
    insetShowBarOutline,
    insetBarOutlineColor,
    insetBarStrokeWidth,
    insetShowGrid,
    insetGridColor,
    insetErrorStrokeWidth,
    insetXFontSize,
    insetYFontSize,
    insetXLabelAngle,
    insetShowPoints,
    insetPointSize,
    insetPointColor,
    formula,
    replicateSums,
    fileName,
    onXRangeChange,
    onResetXRange,
    xZoomed,
  },
  ref
) {
  const tr = useT();
  const activeStats = stats.filter((s) => s.enabled);
  const combinedRef = useRef<SVGSVGElement | null>(null);
  const facetRefs = useRef<Record<string, SVGSVGElement | null>>({});
  const [statsDataMode, setStatsDataMode] = useState<"raw" | "corrected">("corrected");
  const [statsAnnotations, setStatsAnnotations] = useState<AnnotationSpec | null>(null);
  const [statsSummary, setStatsSummary] = useState<string | null>(null);
  const [chartOpen, setChartOpen] = useState(true);
  const [replicateTableOpen, setReplicateTableOpen] = useState(false);
  const [insetOpen, setInsetOpen] = useState(true);
  useEffect(() => {
    if (showInset) setInsetOpen(true);
  }, [showInset]);
  const barRef = useRef<SVGSVGElement | null>(null);

  const statsGroups = useMemo(() => {
    if (!showInset || !replicateSums || replicateSums.length < 2) return null;
    // Only include conditions that are enabled (match activeStats)
    const activeLabels = new Set(activeStats.map((s) => s.prefix));
    const filtered = replicateSums.filter((rs) => activeLabels.has(rs.prefix));
    if (filtered.length < 2) return null;
    return filtered.map((rs) => ({
      name: rs.label,
      values: rs.repSums.map((rep) => (statsDataMode === "raw" ? rep.rawSum : rep.corrSum)),
    }));
  }, [showInset, replicateSums, activeStats, statsDataMode]);

  // Hash signature of activeStats keyed on prefix/label/color/enabled +
  // active column indices. Lifted out of the deps array so eslint can
  // statically check it (the inline expression form fails the
  // "complex expression in dependency array" check).
  const activeStatsKey = activeStats
    .map(
      (s) =>
        s.prefix +
        "|" +
        s.label +
        "|" +
        s.color +
        "|" +
        s.enabled +
        ":" +
        (s.activeColIndices || s.colIndices).join(":")
    )
    .join(",");

  const series = useMemo<SeriesItem[]>(() => {
    if (activeStats.length === 0) return [];
    return activeStats.map((cond) => {
      const sm = smooth(cond.means, smoothWidth);
      const ssd = smooth(cond.sds, smoothWidth);
      const rows: SeriesRow[] = [];
      for (let r = xStart; r <= xEnd && r < cond.means.length; r++) {
        rows.push({ t: r, mean: sm[r], sd: ssd[r] });
      }
      return {
        prefix: cond.prefix,
        label: cond.label,
        color: cond.color,
        n: (cond.activeColIndices || cond.colIndices).length,
        rows,
      };
    });
    // `activeStats` is read via `activeStatsKey` (an opaque hash of
    // prefix/label/color/enabled/colIndices) so cosmetic-only edits to
    // the conditions don't invalidate this memo.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeStats.length, activeStatsKey, xStart, xEnd, smoothWidth]);

  const ts = timeStep || 1;
  const bUnit = baseUnit || "s";
  const dUnit = displayUnit || bUnit;
  const convFactor = convertTime(1, bUnit, dUnit);
  const xLabelText = `Time (${dUnit})`;
  const displayXStart = xStart * ts * convFactor;
  const displayXEnd = xEnd * ts * convFactor;

  // Drag-to-window: the Chart reports the brushed window in display-time
  // units; map it back to row indices (the inverse of `displayX = row * ts *
  // convFactor`) and hand it to App. Rounded to whole rows — brushing is
  // imprecise and rows are the underlying time-points the window slices on.
  const tsConv = ts * convFactor || 1;
  const onBrush = useCallback(
    (d0: number, d1: number) => {
      if (!onXRangeChange) return;
      const r0 = Math.round(d0 / tsConv);
      const r1 = Math.round(d1 / tsConv);
      if (r1 > r0) onXRangeChange(r0, r1);
    },
    [onXRangeChange, tsConv]
  );

  const displaySeries = useMemo(() => {
    return series.map((s) => ({
      ...s,
      rows: s.rows.map((r: SeriesRow) => ({ ...r, t: r.t * ts * convFactor })),
    }));
  }, [series, ts, convFactor]);

  const baseName = fileBaseName(fileName, "rlu_timecourse");

  React.useImperativeHandle(
    ref,
    () => ({
      downloadMain: () => {
        if (faceted) {
          displaySeries.forEach((s) =>
            downloadSvg(facetRefs.current[s.prefix], `${baseName}_${s.label}.svg`)
          );
        } else {
          downloadSvg(combinedRef.current, `${baseName}_combined.svg`);
        }
        if (showInset && barRef.current) {
          const suffix = statsDataMode === "raw" ? "raw" : "corrected";
          downloadSvg(barRef.current, `${baseName}_barplot_${suffix}.svg`);
        }
      },
      downloadMainPng: () => {
        if (faceted) {
          displaySeries.forEach((s) =>
            downloadPng(facetRefs.current[s.prefix], `${baseName}_${s.label}.png`)
          );
        } else {
          downloadPng(combinedRef.current, `${baseName}_combined.png`);
        }
        if (showInset && barRef.current) {
          const suffix = statsDataMode === "raw" ? "raw" : "corrected";
          downloadPng(barRef.current, `${baseName}_barplot_${suffix}.png`);
        }
      },
    }),
    [faceted, displaySeries, showInset, statsDataMode, baseName]
  );

  if (activeStats.length === 0)
    return (
      <div
        style={{
          padding: "60px 20px",
          textAlign: "center",
          color: "var(--text-faint)",
          fontSize: 14,
        }}
      >
        No conditions or samples selected. Enable at least one to display the plot.
      </div>
    );

  const insetBarProps = {
    series,
    insetFillOpacity,
    insetBarWidth,
    insetBarGap,
    insetW,
    insetH,
    insetErrorType,
    insetShowBarOutline,
    insetBarOutlineColor,
    insetBarStrokeWidth,
    insetShowGrid,
    insetGridColor,
    insetErrorStrokeWidth,
    insetXFontSize,
    insetYFontSize,
    insetXLabelAngle,
    plotBg,
    plotTitle: title || null,
    plotSubtitle: subtitle || null,
    replicateSums,
  };

  const isCorrected = statsDataMode === "corrected";
  const sumKey = isCorrected ? "corrSum" : "rawSum";
  const sumLabel = isCorrected ? "Corrected Sum" : "Raw Sum";
  const csvFileName = isCorrected ? `${baseName}_corrected_sums.csv` : `${baseName}_raw_sums.csv`;

  const IntegralTile = showInset ? (
    <div
      style={{
        marginTop: 16,
        borderRadius: 10,
        border: "1px solid var(--border-strong)",
        background: "var(--surface)",
        overflow: "hidden",
      }}
    >
      <button
        onClick={() => setInsetOpen((o) => !o)}
        style={{
          width: "100%",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "10px 14px",
          background: "none",
          border: "none",
          cursor: "pointer",
          fontFamily: "inherit",
        }}
      >
        <span
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            fontSize: 13,
            fontWeight: 600,
            color: "var(--text-muted)",
          }}
        >
          <span
            className={"dv-disclosure" + (insetOpen ? " dv-disclosure-open" : "")}
            aria-hidden="true"
          />
          Barplot (Σ of plotted values)
        </span>
      </button>
      {insetOpen && (
        <div style={{ padding: "0 16px 16px" }}>
          {/* Toggle */}
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
            <span style={{ fontSize: 13, fontWeight: 600, color: "var(--text-muted)" }}>
              Integral:
            </span>
            <button
              onClick={() => setStatsDataMode("raw")}
              style={{
                padding: "5px 14px",
                borderRadius: 6,
                fontSize: 12,
                fontWeight: 600,
                background: statsDataMode === "raw" ? "var(--cta-primary-bg)" : "var(--surface)",
                color: statsDataMode === "raw" ? "var(--on-accent)" : "var(--text-faint)",
                border: `1px solid ${statsDataMode === "raw" ? "var(--cta-primary-bg)" : "var(--border-strong)"}`,
                cursor: "pointer",
                fontFamily: "inherit",
              }}
            >
              Σ Raw
            </button>
            <button
              onClick={() => setStatsDataMode("corrected")}
              style={{
                padding: "5px 14px",
                borderRadius: 6,
                fontSize: 12,
                fontWeight: 600,
                background:
                  statsDataMode === "corrected" ? "var(--cta-primary-bg)" : "var(--surface)",
                color: statsDataMode === "corrected" ? "var(--on-accent)" : "var(--text-faint)",
                border: `1px solid ${statsDataMode === "corrected" ? "var(--cta-primary-bg)" : "var(--border-strong)"}`,
                cursor: "pointer",
                fontFamily: "inherit",
              }}
            >
              Σ Baseline-corrected
            </button>
          </div>

          {/* The inner .dv-plot-card is the actual plot canvas (stays white
              for export consistency + dimmed via filter in dark mode); the
              outer IntegralTile uses themed surface colors so its chrome
              follows dark mode. */}
          <div
            className="dv-plot-card"
            style={{
              background: "var(--plot-card-bg)",
              borderRadius: 8,
              padding: 12,
              border: "1px solid var(--plot-card-border)",
            }}
          >
            <InsetBarplot
              ref={barRef}
              {...insetBarProps}
              insetW={Math.max(200, series.length * 100 + 86)}
              insetH={420}
              insetYMin={insetYMin}
              insetYMax={insetYMax}
              corrected={isCorrected}
              annotations={statsAnnotations}
              statsSummary={statsSummary}
              insetXFontSize={12}
              insetYFontSize={11}
              showPoints={insetShowPoints}
              pointSize={insetPointSize}
              pointColor={insetPointColor}
            />
          </div>

          {/* CSV table */}
          {replicateSums && replicateSums.length > 0 && (
            <div
              className="dv-panel"
              style={{ marginTop: 12, background: "var(--surface-subtle)", marginBottom: 0 }}
            >
              <div
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                }}
              >
                <div
                  onClick={() => setReplicateTableOpen((o) => !o)}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 10,
                    cursor: "pointer",
                    userSelect: "none",
                    flex: 1,
                  }}
                >
                  <span
                    className={"dv-disclosure" + (replicateTableOpen ? " dv-disclosure-open" : "")}
                    aria-hidden="true"
                  />
                  <h3
                    style={{
                      margin: 0,
                      fontSize: 14,
                      fontWeight: 700,
                      color: "var(--text)",
                      letterSpacing: "0.2px",
                    }}
                  >
                    {tr("aequorin.pa.perReplicate")}
                  </h3>
                </div>
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 6,
                    marginLeft: "auto",
                    flexShrink: 0,
                  }}
                >
                  {/* Open the same per-replicate Σ data directly in the
                      Group Plot tool (boxplot / violin / raincloud / bar).
                      Bypasses the export-CSV-then-re-upload round trip:
                      the data is already clean (one row per replicate,
                      Condition + Σ value), so we hand it off via
                      localStorage and let boxplot's mount-time hand-off
                      consumer skip its own upload step entirely. */}
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      const rows = replicateSums.flatMap((rs) =>
                        rs.repSums.map((rep) => [
                          rs.prefix,
                          rep[sumKey] != null ? rep[sumKey].toFixed(6) : "",
                        ])
                      );
                      const header = ["Condition", sumLabel];
                      // Quote on \r too — a lone-CR cell would otherwise split
                      // a row when Boxplot re-parses. (Not buildCsvString: its
                      // formula-injection guard would prefix legit condition
                      // names like "-control"/"+drug" with a quote, and this
                      // payload is re-parsed in-app, never opened in a sheet.)
                      const csv = [header, ...rows]
                        .map((r) =>
                          r
                            .map((c) =>
                              /[",\r\n]/.test(String(c)) ? `"${c.replace(/"/g, '""')}"` : c
                            )
                            .join(",")
                        )
                        .join("\n");
                      setHandoff({
                        tool: "boxplot",
                        csv,
                        mode: "long",
                        source: "RLU timecourse — Σ barplot",
                        fileName: csvFileName.replace(/\.csv$/i, "") + "_boxplot.csv",
                        // Send the standard scientific label for what
                        // Σ-of-luminescence represents (the discrete
                        // integral over time-points, i.e. area under
                        // the time-course curve up to a constant Δt
                        // factor that's the same for every replicate).
                        // Without this hint the boxplot would auto-
                        // derive "Raw Sum" / "Corrected Sum" from the
                        // CSV column header — an implementation detail
                        // most users don't recognise.
                        yLabel: "A.U.C.",
                      });
                      // Single shell-aware path: `navigateToTool` prefers
                      // the SPA router when registered
                      // (`window.__plottrSpaNavigate`), and falls back to
                      // a top-level `window.location.assign("boxplot.html")`
                      // for legacy / standalone-page deploys. Either way,
                      // Group Plot's mount-time `consumeHandoff()` finds
                      // the localStorage payload we just wrote and applies
                      // it.
                      navigateToTool("boxplot");
                    }}
                    className="dv-btn dv-btn-secondary"
                    // Match the sibling ⬇ CSV chip's vertical padding
                    // (`dv-btn-dl` is `8px 10px`); the default secondary
                    // padding (`6px 14px`) makes this button visibly
                    // shorter when they sit next to each other.
                    style={{ flexShrink: 0, padding: "8px 14px" }}
                    title={tr("aequorin.pa.openInBoxplotTitle")}
                  >
                    {tr("aequorin.pa.openInBoxplot")}
                  </button>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      const rows = replicateSums.flatMap((rs) =>
                        rs.repSums.map((rep, ri) => [
                          rs.prefix,
                          `Rep ${ri + 1}`,
                          rep[sumKey] != null ? rep[sumKey].toFixed(6) : "",
                        ])
                      );
                      downloadCsv(["Condition", "Replicate", sumLabel], rows, csvFileName);
                      flashSaved(e.currentTarget);
                    }}
                    className="dv-btn dv-btn-dl"
                    style={{ flexShrink: 0 }}
                  >
                    ⬇ CSV
                  </button>
                </div>
              </div>
              {replicateTableOpen && (
                <table
                  style={{ borderCollapse: "collapse", fontSize: 11, width: "100%", marginTop: 10 }}
                >
                  <thead>
                    <tr style={{ borderBottom: "2px solid var(--border-strong)" }}>
                      {["Condition", "Replicate", sumLabel].map((h) => (
                        <th
                          key={h}
                          style={{
                            padding: "3px 8px",
                            textAlign: "left",
                            color: "var(--text-muted)",
                            fontWeight: 700,
                          }}
                        >
                          {h}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {replicateSums.map((rs) =>
                      rs.repSums.map((rep, ri) => (
                        <tr
                          key={`${rs.prefix}-${ri}`}
                          style={{ borderBottom: "1px solid var(--border)" }}
                        >
                          <td style={{ padding: "3px 8px", color: "var(--text)", fontWeight: 600 }}>
                            {rs.label}
                          </td>
                          <td style={{ padding: "3px 8px", color: "var(--text-muted)" }}>
                            Rep {ri + 1}
                          </td>
                          <td
                            style={{
                              padding: "3px 8px",
                              color: "var(--text)",
                              fontFamily: "monospace",
                            }}
                          >
                            {rep[sumKey] != null ? rep[sumKey].toFixed(4) : "—"}
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              )}
            </div>
          )}

          {/* Stats panel */}
          {statsGroups && (
            <div style={{ marginTop: 12 }}>
              <AequorinStatsPanel
                groups={statsGroups}
                fileStem={`${baseName}_stats`}
                onAnnotationChange={setStatsAnnotations}
                onSummaryChange={setStatsSummary}
                errorBarLabel={AQ_ERROR_BAR_LABELS[insetErrorType]}
              />
            </div>
          )}
        </div>
      )}
    </div>
  ) : null;

  // ── Collapsible time-course chart tile ──
  // Same two-level theming as IntegralTile: outer is themed chrome (goes
  // dark in dark mode), inner wraps the chart SVG in a .dv-plot-card so
  // the plot canvas stays white-and-dimmed for export consistency.
  const ChartTile = (chartContent: React.ReactNode) => (
    <div
      style={{
        borderRadius: 10,
        border: "1px solid var(--border-strong)",
        background: "var(--surface)",
        overflow: "hidden",
      }}
    >
      <button
        onClick={() => setChartOpen(!chartOpen)}
        style={{
          width: "100%",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "10px 14px",
          background: "none",
          border: "none",
          cursor: "pointer",
          fontFamily: "inherit",
        }}
      >
        <span
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            fontSize: 13,
            fontWeight: 600,
            color: "var(--text-muted)",
          }}
        >
          <span
            className={"dv-disclosure" + (chartOpen ? " dv-disclosure-open" : "")}
            aria-hidden="true"
          />
          Time-course plot
        </span>
      </button>
      {chartOpen && (
        <div style={{ padding: "0 12px 12px" }}>
          <div
            className="dv-plot-card"
            style={{
              background: "var(--plot-card-bg)",
              borderRadius: 8,
              border: "1px solid var(--plot-card-border)",
              padding: 12,
            }}
          >
            {chartContent}
          </div>
        </div>
      )}
    </div>
  );

  if (faceted) {
    const nCols = Math.min(displaySeries.length, 3);
    return (
      <div>
        {ChartTile(
          <div
            style={{
              display: "grid",
              gridTemplateColumns: `repeat(${nCols}, 1fr)`,
              gap: 16,
              alignItems: "stretch",
            }}
          >
            {displaySeries.map((s) => {
              const chartProps = {
                series: [s],
                xStart: displayXStart,
                xEnd: displayXEnd,
                yMin,
                yMax,
                vbW: 400,
                vbH: Math.max(80, Math.round((260 * plotHeight) / 420)),
                xLabel: xLabelText,
                yLabel: formula === "none" ? "RLU (raw)" : "[Ca²⁺] (µM)",
                plotBg,
                showGrid,
                lineWidth,
                ribbonOpacity,
                gridColor,
                plotTitle: s.label,
                svgLegend: null,
              };
              return (
                <FacetChartItem
                  key={s.prefix}
                  s={s}
                  facetRefs={facetRefs}
                  chartProps={chartProps}
                />
              );
            })}
          </div>
        )}
        {IntegralTile}
      </div>
    );
  }

  return (
    <div>
      {ChartTile(
        <>
          <Chart
            ref={combinedRef}
            series={displaySeries}
            xStart={displayXStart}
            xEnd={displayXEnd}
            yMin={yMin}
            yMax={yMax}
            vbW={800}
            vbH={plotHeight}
            xLabel={xLabelText}
            yLabel={formula === "none" ? "RLU (raw)" : "[Ca²⁺] (µM)"}
            plotBg={plotBg}
            showGrid={showGrid}
            lineWidth={lineWidth}
            ribbonOpacity={ribbonOpacity}
            gridColor={gridColor}
            plotTitle={title || null}
            plotSubtitle={subtitle || null}
            svgLegend={[
              {
                id: "legend-samples",
                title: null,
                items: displaySeries.map((s) => ({
                  label: `${s.label} (n=${s.n})`,
                  color: s.color,
                  shape: "line",
                })),
              },
            ]}
            onBrush={onXRangeChange ? onBrush : undefined}
          />
          {onXRangeChange && (
            <div
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: 10,
                margin: "6px 2px 0",
              }}
            >
              <p style={{ margin: 0, fontSize: 11, color: "var(--text-faint)" }}>
                {tr("aequorin.pa.dragTip")}
                {xZoomed ? tr("aequorin.pa.dragTipClear") : ""}
              </p>
              {onResetXRange && xZoomed && (
                <button
                  type="button"
                  onClick={onResetXRange}
                  className="dv-btn dv-btn-secondary"
                  style={{ padding: "4px 10px", fontSize: 11, flexShrink: 0 }}
                  title={tr("aequorin.pa.resetTitle")}
                >
                  {tr("aequorin.pa.clear")}
                </button>
              )}
            </div>
          )}
        </>
      )}
      {IntegralTile}
    </div>
  );
});

// ── ConditionEditor ──────────────────────────────────────────────────────────
// Sidebar "Conditions" tile editor — toggle per-condition enable, edit
// label/color. Rendered inside PlotControls' ControlSection.

export function ConditionEditor({ conditions, onChange }: ConditionEditorProps) {
  const update = (i: number, key: keyof Condition, val: unknown) =>
    onChange(conditions.map((c, j) => (j === i ? { ...c, [key]: val } : c)));
  const toggle = (i: number) =>
    onChange(conditions.map((c, j) => (j === i ? { ...c, enabled: !c.enabled } : c)));
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
      {conditions.map((c, i) => (
        <div
          key={c.prefix}
          style={{
            display: "flex",
            alignItems: "center",
            gap: 5,
            padding: "4px 8px",
            borderRadius: 6,
            fontSize: 12,
            background: c.enabled ? "var(--surface-sunken)" : "var(--surface-subtle)",
            opacity: c.enabled ? 1 : 0.4,
            border: "1px solid var(--border-strong)",
          }}
        >
          <input
            type="checkbox"
            checked={c.enabled}
            onChange={() => toggle(i)}
            style={{ accentColor: c.color, flexShrink: 0 }}
          />
          <ColorInput value={c.color} onChange={(v) => update(i, "color", v)} size={20} />
          <input
            value={c.label}
            onChange={(e) => update(i, "label", e.target.value)}
            style={{
              flex: 1,
              minWidth: 0,
              background: "var(--surface)",
              border: "1px solid var(--border-strong)",
              borderRadius: 4,
              color: "var(--text)",
              padding: "2px 5px",
              fontSize: 12,
              fontFamily: "inherit",
            }}
          />
          <span style={{ color: "var(--text-faint)", fontSize: 10, flexShrink: 0 }}>
            ({c.colIndices.length})
          </span>
        </div>
      ))}
    </div>
  );
}

// ── SampleSelectionOverlay ───────────────────────────────────────────────────
// Sticky "Sample selection" pill + popover grid. Lets the user toggle
// individual replicates on/off without leaving the plot step.

export function SampleSelectionOverlay({
  showColumnOverlay,
  setShowColumnOverlay,
  poolReplicates,
  colInfo,
  columnEnabled,
  handleColumnToggle,
  conditions,
}: SampleSelectionOverlayProps) {
  const tr = useT();
  const labelByPrefix: Record<string, string> = {};
  (conditions || []).forEach((c) => {
    if (c && c.prefix != null) labelByPrefix[c.prefix] = c.label ?? c.prefix;
  });
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-start" }}>
      <span
        style={{
          fontSize: 9,
          fontWeight: 700,
          letterSpacing: "0.04em",
          textTransform: "uppercase",
          color: "var(--text-faint)",
          marginBottom: 2,
        }}
      >
        {tr("aequorin.pa.samples")}
      </span>
      <div style={{ position: "relative", display: "inline-block" }}>
        <button
          onClick={() => setShowColumnOverlay(!showColumnOverlay)}
          aria-pressed={showColumnOverlay}
          style={{
            padding: "6px 14px",
            borderRadius: 8,
            fontSize: 12,
            fontWeight: 600,
            fontFamily: "inherit",
            cursor: "pointer",
            background: showColumnOverlay ? "var(--warning-bg)" : "var(--surface)",
            color: "var(--warning-text)",
            border: `1px solid ${showColumnOverlay ? "var(--warning-text)" : "var(--warning-border)"}`,
          }}
        >
          {showColumnOverlay ? tr("aequorin.pa.close") : tr("aequorin.pa.sampleSelection")}
        </button>
        {showColumnOverlay && (
          <div
            style={{
              position: "absolute",
              top: "100%",
              left: 0,
              marginTop: 6,
              width: 420,
              background: "var(--surface)",
              borderRadius: 10,
              border: "1px solid var(--warning-border)",
              boxShadow: "var(--shadow-lg)",
              padding: "12px 14px",
              maxHeight: 360,
              overflowY: "auto",
            }}
          >
            <div
              style={{
                display: "flex",
                flexWrap: "wrap",
                gap: 8,
                maxHeight: 260,
                overflowY: "auto",
                padding: 2,
              }}
            >
              {(() => {
                interface SampleGroup {
                  name: string;
                  cols: ColInfo[];
                }
                const groups: SampleGroup[] = [];
                const seen: Record<string, SampleGroup> = {};
                colInfo.forEach((c) => {
                  if (!seen[c.h]) {
                    seen[c.h] = { name: c.h, cols: [] };
                    groups.push(seen[c.h]);
                  }
                  seen[c.h].cols.push(c);
                });
                return groups.map((g) => {
                  const headerLabel = poolReplicates ? (labelByPrefix[g.name] ?? g.name) : g.name;
                  return (
                    <div
                      key={g.name}
                      style={{
                        background: "var(--surface-subtle)",
                        borderRadius: 6,
                        border: "1px solid var(--border)",
                        padding: "5px 7px",
                        minWidth: 0,
                      }}
                    >
                      <div
                        style={{
                          fontSize: 10,
                          fontWeight: 700,
                          color: "var(--text-muted)",
                          marginBottom: 3,
                          whiteSpace: "nowrap",
                          overflow: "hidden",
                          textOverflow: "ellipsis",
                        }}
                      >
                        {headerLabel}
                      </div>
                      <div style={{ display: "flex", flexWrap: "wrap", gap: 3 }}>
                        {g.cols.map(({ h, i, rep }) => {
                          const enabled = columnEnabled[i] !== false;
                          const showRep = g.cols.length > 1 || !poolReplicates;
                          return (
                            <label
                              key={i}
                              style={{
                                display: "flex",
                                alignItems: "center",
                                gap: 3,
                                padding: "2px 6px",
                                background: enabled ? "var(--surface)" : "var(--surface-subtle)",
                                borderRadius: 4,
                                border: `1px solid ${enabled ? "var(--border-strong)" : "var(--border)"}`,
                                opacity: enabled ? 1 : 0.45,
                                fontSize: 10,
                                cursor: "pointer",
                                userSelect: "none",
                              }}
                            >
                              <input
                                type="checkbox"
                                checked={enabled}
                                onChange={(e) => handleColumnToggle(i, e.target.checked)}
                                style={{
                                  accentColor: "var(--warning-text)",
                                  width: 12,
                                  height: 12,
                                }}
                              />
                              {showRep ? `rep${rep}` : h}
                            </label>
                          );
                        })}
                      </div>
                    </div>
                  );
                });
              })()}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
